using Microsoft.AspNetCore.Mvc;
using System.IO;
using Microsoft.AspNetCore.StaticFiles;

namespace YourNamespace
{
    [Route("api/[controller]")]
    [ApiController]
    public class FileController : ControllerBase
    {
        // GET api/file/{filename}
        [HttpGet("{filename}")]
        public IActionResult Get(string filename)
        {
            if (!System.IO.File.Exists(Path.Combine("wwwroot", "uploads", filename))) 
                return NotFound(); // Return 404 status code if file not found in upload directory
            
            var contentTypeProvider = new FileExtensionContentTypeProvider();
            contentTypeProvider.TryGetContentType(filename, out string contentType); // Get the MIME type based on the file extension

            byte[] bytes = System.IO.File.ReadAllBytes(Path.Combine("wwwroot", "uploads", filename)); 
            
            return File(bytes, contentType ?? "application/octet-stream");  // Returns the file with appropriate MIME type. If unknown extension then defaults to 'application/octet-stream'
        }
    }
